(window.webpackJsonp=window.webpackJsonp||[]).push([[785],{778:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * Definition for singly-linked list.\\n * function ListNode(val) {\\n *     this.val = val;\\n *     this.next = null;\\n * }\\n */</span>\\n\\n<span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{ListNode}</span> <span class=\\"hljs-variable\\">head</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{boolean}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> hasCycle = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">head</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> fast=head,slow=head\\n  <span class=\\"hljs-keyword\\">while</span>(fast &amp;&amp; fast.next){\\n    slow=slow.next\\n    fast=fast.next.next\\n    <span class=\\"hljs-keyword\\">if</span>(fast===slow)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-literal\\">true</span>\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-literal\\">false</span>\\n};\\n</code></pre>\\n"],"titleSlug":"linked-list-cycle","hasThinking":true,"thinking":"<hr>\\n<p>\u601d\u8def\uff1a</p>\\n<p>\u53cc\u6307\u9488\uff0c<code>fast</code>\u6bcf\u6b21\u8df32\u4e0b\uff0c<code>slow</code>\u6bcf\u6b21\u8df31\u4e0b\uff0c\u5982\u679c<code>fast</code>\u80fd\u91cd\u9047<code>slow</code>\uff0c\u8bf4\u660e\u6709\u73af\u3002</p>\\n","content":"<p>\u7ed9\u5b9a\u4e00\u4e2a\u94fe\u8868\uff0c\u5224\u65ad\u94fe\u8868\u4e2d\u662f\u5426\u6709\u73af\u3002</p>\\n\\n<p>\u5982\u679c\u94fe\u8868\u4e2d\u6709\u67d0\u4e2a\u8282\u70b9\uff0c\u53ef\u4ee5\u901a\u8fc7\u8fde\u7eed\u8ddf\u8e2a <code>next</code> \u6307\u9488\u518d\u6b21\u5230\u8fbe\uff0c\u5219\u94fe\u8868\u4e2d\u5b58\u5728\u73af\u3002 \u4e3a\u4e86\u8868\u793a\u7ed9\u5b9a\u94fe\u8868\u4e2d\u7684\u73af\uff0c\u6211\u4eec\u4f7f\u7528\u6574\u6570 <code>pos</code> \u6765\u8868\u793a\u94fe\u8868\u5c3e\u8fde\u63a5\u5230\u94fe\u8868\u4e2d\u7684\u4f4d\u7f6e\uff08\u7d22\u5f15\u4ece 0 \u5f00\u59cb\uff09\u3002 \u5982\u679c <code>pos</code> \u662f <code>-1</code>\uff0c\u5219\u5728\u8be5\u94fe\u8868\u4e2d\u6ca1\u6709\u73af\u3002<strong>\u6ce8\u610f\uff1a<code>pos</code> \u4e0d\u4f5c\u4e3a\u53c2\u6570\u8fdb\u884c\u4f20\u9012</strong>\uff0c\u4ec5\u4ec5\u662f\u4e3a\u4e86\u6807\u8bc6\u94fe\u8868\u7684\u5b9e\u9645\u60c5\u51b5\u3002</p>\\n\\n<p>\u5982\u679c\u94fe\u8868\u4e2d\u5b58\u5728\u73af\uff0c\u5219\u8fd4\u56de <code>true</code> \u3002 \u5426\u5219\uff0c\u8fd4\u56de <code>false</code> \u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u8fdb\u9636\uff1a</strong></p>\\n\\n<p>\u4f60\u80fd\u7528 <em>O(1)</em>\uff08\u5373\uff0c\u5e38\u91cf\uff09\u5185\u5b58\u89e3\u51b3\u6b64\u95ee\u9898\u5417\uff1f</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2018/12/07/circularlinkedlist.png\\" style=\\"height: 97px; width: 300px;\\"></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>head = [3,2,0,-4], pos = 1\\n<strong>\u8f93\u51fa\uff1a</strong>true\\n<strong>\u89e3\u91ca\uff1a</strong>\u94fe\u8868\u4e2d\u6709\u4e00\u4e2a\u73af\uff0c\u5176\u5c3e\u90e8\u8fde\u63a5\u5230\u7b2c\u4e8c\u4e2a\u8282\u70b9\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b&nbsp;2\uff1a</strong></p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2018/12/07/circularlinkedlist_test2.png\\" style=\\"height: 74px; width: 141px;\\"></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>head = [1,2], pos = 0\\n<strong>\u8f93\u51fa\uff1a</strong>true\\n<strong>\u89e3\u91ca\uff1a</strong>\u94fe\u8868\u4e2d\u6709\u4e00\u4e2a\u73af\uff0c\u5176\u5c3e\u90e8\u8fde\u63a5\u5230\u7b2c\u4e00\u4e2a\u8282\u70b9\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2018/12/07/circularlinkedlist_test3.png\\" style=\\"height: 45px; width: 45px;\\"></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>head = [1], pos = -1\\n<strong>\u8f93\u51fa\uff1a</strong>false\\n<strong>\u89e3\u91ca\uff1a</strong>\u94fe\u8868\u4e2d\u6ca1\u6709\u73af\u3002\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li>\u94fe\u8868\u4e2d\u8282\u70b9\u7684\u6570\u76ee\u8303\u56f4\u662f <code>[0, 10<sup>4</sup>]</code></li>\\n\\t<li><code>-10<sup>5</sup> &lt;= Node.val &lt;= 10<sup>5</sup></code></li>\\n\\t<li><code>pos</code> \u4e3a <code>-1</code> \u6216\u8005\u94fe\u8868\u4e2d\u7684\u4e00\u4e2a <strong>\u6709\u6548\u7d22\u5f15</strong> \u3002</li>\\n</ul>\\n","title":"141. \u73af\u5f62\u94fe\u8868","relatedTags":["\u94fe\u8868","\u53cc\u6307\u9488"],"difficult":"Easy","lang":["javascript"],"uniqueID":"141"}')}}]);